const Q_COMMERCE_1999=[{"id": "objective>Commerce>1999>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The conversion of raw material into finished products creates</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Marginal utility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Place utility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Form utility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Time utility</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Form utility is created by changing the form of raw materials into finished goods e.g production in agriculture or manufacturing creates form utility.</div>", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE"}, {"id": "objective>Commerce>1999>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Commerce makes it possible for man to live in a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">complex and organized society</div>", "<div style=\"font-family:Cambria;font-size:17px;\">society characterized by subsistency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">society characterized by dependency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">simple and organized society</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Commerce makes it possible for man to live in a 'complex and organized society'. Commerce involves the exchange of goods and services, and it facilitates the distribution of goods from producers to consumers. This leads to an interdependence among individuals and businesses, creating a complex and organized society.</div>", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE"}, {"id": "objective>Commerce>1999>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the information below to answer questions below <br/> Aboki Plc, became the insolvent and decided to wind up to meet the legitimate claims of its creditors.  <br/> Babalawee was called in to manage the dissolution. <br/>  <br/> After paying the debts of aboki Plc, the balance goes to?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Aboki Plc</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Babalawee</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shareholders</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Creditors</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During business liquidation, a company's assets will be used to pay off its debts and leftover money will go to the shareholders. </div>", "topic": "BUSINESS UNIT: MERGER : DISSOLUTION AND LIQUIDATION"}, {"id": "objective>Commerce>1999>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the information below to answer questions below <br/> Aboki Plc, became the insolvent and decided to wind up to meet the legitimate claims of its creditors.  <br/> Babalawee was called in to manage the dissolution. <br/> Babalawee is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a claimant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a manager </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an assessor </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a receiver</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the context of a company winding up, a receiver is an individual appointed to manage the company's assets and operations to ensure that the creditors' claims are met. Therefore, Babalawee is a receiver.</div>", "topic": "BUSINESS UNIT: MERGER : DISSOLUTION AND LIQUIDATION"}, {"id": "objective>Commerce>1999>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A common requirement for public and private limited companies in Nigeria is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a shareholder cannot transfer his shares to someone else without permission from other shareholders</div>", "<div style=\"font-family:Cambria;font-size:17px;\">their annual account are made available to the Corporate Affairs Commission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shares can be offered for sale on the stock exchange</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shares can be offered for sale through an issuing house</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The account of both private and public limited company must be annually prepared and made available to the CAC.</div>", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : FEATURES AND IMPORTANCE"}, {"id": "objective>Commerce>1999>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The primary motive behind an individual engaging in production is to?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fully engaged all the factors of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">make available goods and services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">meets projected profit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">meet basic human needs</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The primary motive behind an individual engaging in production is to meet projected profit. While other options like making available goods and services, and meeting basic human needs can be secondary motives, the primary motive is usually to make a profit.</div>", "topic": "PRODUCTION : FACTORS OF PRODUCTION"}, {"id": "objective>Commerce>1999>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Musa obtains wool from his sheep, spins and transforms it into cloth which he sells to consumers. This is a form of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">vertical integration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">horizontal integration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">forward integration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">backward integration</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Vertical merger/integration is the coming together of firms at different stages of production process. It is therefore a method of linking the various stages of production from the raw material stages of production from raw material stage to the finished product.</div>", "topic": "BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER"}, {"id": "objective>Commerce>1999>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A company has an authorized capital of 40 million shares at N1 per share, out of which 32 million shares have been issued and fully paid-up. The remaining 8 million shares have</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">been issued but have not been paid-up</div>", "<div style=\"font-family:Cambria;font-size:17px;\">been applied for but not issued</div>", "<div style=\"font-family:Cambria;font-size:17px;\">not been paid-up</div>", "<div style=\"font-family:Cambria;font-size:17px;\">not yet been issued</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Unissued capital is an authorized capital that has not yet been issued as shares. The 8 million shares is called unissued capital.</div>", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : FEATURES AND IMPORTANCE"}, {"id": "objective>Commerce>1999>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An abridged version of a company's income statement for 11993 contains the following information: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">                                                 </td><td style=\"border:1px solid black;text-align:center;\">  #(m)</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Turnover                                 </td><td style=\"border:1px solid black;text-align:center;\">   286.5</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">cost of goods sold                   </td><td style=\"border:1px solid black;text-align:center;\">147.5</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">overhead and other expenses  </td><td style=\"border:1px solid black;text-align:center;\">85.5</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Taxes due for the year              </td><td style=\"border:1px solid black;text-align:center;\">26.9</td></tr></table></div> <br/> What was the company's profit before tax for 1993?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#26.9 million</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#53.5million</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#139.2million</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#286.5million</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gross profit = Sales - Cost of goods sold <br/> = 286.5m - 147.5m <br/>  = #139m <br/>  <br/> Net profit ( before tax) = Gross profit - Overhead expenses <br/> = 139m  - 85.5m <br/> = #53.5m</div>", "topic": "FINANCING BUSINESS : PROFIT"}, {"id": "objective>Commerce>1999>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A business whose owners enjoys loan facilities on the basis of personal goodwill is a?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">commercial bank</div>", "<div style=\"font-family:Cambria;font-size:17px;\">thrift society</div>", "<div style=\"font-family:Cambria;font-size:17px;\">co-operative society</div>", "<div style=\"font-family:Cambria;font-size:17px;\">community bank</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A co-operative society is a business whose owners enjoy loan facilities on the basis of personal goodwill. This is because a co-operative society is a voluntary association of individuals who come together to protect and promote their common interests. They pool their resources together to provide loans to members on the basis of personal goodwill.</div>", "topic": "BUSINESS UNIT: SOLE PROPRIETORSHIP : MEANING AND IMPORTANCE"}, {"id": "objective>Commerce>1999>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not a veritable source of funds to a public limited company?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">government financial grant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">advances and loan from banks</div>", "<div style=\"font-family:Cambria;font-size:17px;\">internally generated funds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">funds from the sale of shares</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The sources of finance or capital available to public limited company are: loans and overdraft, sales of shares, sales of debentures, bill of exchange, equipment leasing, retained profit, trade credits, hire purchases.</div>", "topic": "FINANCING BUSINESS : SOURCE OF FINANCE"}, {"id": "objective>Commerce>1999>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the document below to answer questions below <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> Okon Etim Esin is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Debtor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Creditor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Exporter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Importer</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Okon is a creditor who the document is addressed to by the debtor.</div>", "topic": "TRADE ( 2) : DOCMENT USED IN INTERNATION TRADE"}, {"id": "objective>Commerce>1999>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the document below to answer questions below <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The document represents a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Bill of exchange</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cheque</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Money Order</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Promissory note</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A bill of exchange is an unconditional order in writing addressed by one person to another and signed by the person to whom its is addressed to pay on demand or at a fixed or determinable future time a sum certain in money to the order of a specified person. Therefore, the document above represent a bill of exchange as a foreign trade document.</div>", "topic": "TRADE ( 2) : DOCMENT USED IN INTERNATION TRADE"}, {"id": "objective>Commerce>1999>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The term '5 Net 7' on an invoice means that?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5% discount will be allowed on the price charged if payment is made within seven days</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5% discount will be allowed on the price charged if payment is made after seven days</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5% surcharge will be made unless payment is made within seven days</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> 5% discount will be allowed on the charged if the goods are bought within seven days</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">'5 Net 7' on an invoice means that 5% discount will be allowed on the price charged if payment is made within seven days.</div>", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE"}, {"id": "objective>Commerce>1999>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Kabir receives two quotations. Ade quotes N 100 less 20% trade discount and 20% cash discount while Benson N100 less 30% trade discount and 10% cash discount. If Kabir wants to take advantage and cash discount, then</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the material should be supplied by Ade</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the material should be supplied by both of them</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the material should be supplied by Benson</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Benson should be ask to reduce his trade discount</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ade quotes N 100 less 20% trade discount and 20% cash discount  <br/> Amount given out as total discount is <br/> Trade discount =  100 x 20% <br/> = 20 <br/> Cash discount = (100 - 20)  x20% <br/> =  16 <br/> Total discount = 20 + 16 <br/> = 36 <br/> Kabir pays  = 100 - 36 <br/> = #64 <br/>  <br/>  Benson N100 less 30% trade discount and 10% cash discount <br/> Trade discount = 100  x 30% <br/> = 30 <br/> Cash discount = ( 100 - 30) x 10% <br/> =  7 <br/> Total discount = 30 + 7 <br/> = 37 <br/> Kabir pays = 100 - 37 <br/> = #63 <br/>  <br/> Kabir should take advantage of Bension offer since the total amount paid and cash discount is lesser than that of Ade</div>", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF PAYMENT"}, {"id": "objective>Commerce>1999>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A company which issues a promissory note in lieu of payment for goods purchased</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">can refuse to pay on due date since it is only a promise</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is bound to redeem the note for cash on due date</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is not bound to renew the note before payment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">can return the goods purchase and refuse to pay</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Promissory note is a written promise by one party to make a payment of money at a date in the future. A  promissory note in lieu of payment for goods purchased is bound to redeem the note for cash on due date.</div>", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT"}, {"id": "objective>Commerce>1999>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Kamaldeen is a seller in a hire-purchase agreement with Emeka. By law, Kamaldeen cannot recover the hire purchased goods. This is an instance of a restriction on</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Emeka's right to terminate the agreement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kamaldeen's right to re-hire the Goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Emeka's right to breach the agreement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kamaldeen's right to terminate the agreement</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a hire-purchase agreement, the seller (Kamaldeen in this case) has the right to terminate the agreement and recover the goods if the buyer (Emeka) fails to meet the terms of the agreement (usually failure to make the required payments). However, there are certain restrictions and procedures that must be followed. Therefore, this is an instance of a restriction on Kamaldeen's right to terminate the agreement.</div>", "topic": "LEGAL ASPECT OF BUSINESS: HIRE PURCHASES : MEANING AND TYPES"}, {"id": "objective>Commerce>1999>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main document sent to an importer of goods by the exporter are?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> invoice, consular invoice, certificate of origin, fright note, indent and insurance policy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">indent, bill of lading, certificate of origin, invoice and bill of exchange</div>", "<div style=\"font-family:Cambria;font-size:17px;\">certificate of origin, bill of exchange, insurance policy, indent and bill of lading</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bill of lading, invoice insurance policy, consular invoice, certificate of origin and bill of exchange</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The main documents sent to an importer of goods by the exporter are the indent, bill of lading, certificate of origin, invoice, and bill of exchange. An indent is a purchase order placed by an importer with an exporter. A bill of lading is a document issued by a carrier to a shipper, acknowledging that specified goods have been received on board as cargo. A certificate of origin is a document declaring in which country a commodity or good was manufactured. An invoice is a commercial document that itemizes a transaction between a buyer and a seller. A bill of exchange is a binding agreement by one party to pay a fixed amount of cash to another party on demand or at a predetermined date.</div>", "topic": "TRADE ( 2) : DOCMENT USED IN INTERNATION TRADE"}, {"id": "objective>Commerce>1999>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The document that indicate instant payment of cash for goods whenever the are delivered is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">credit note</div>", "<div style=\"font-family:Cambria;font-size:17px;\">proforma invoice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debit note</div>", "<div style=\"font-family:Cambria;font-size:17px;\">statement of account</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A proforma invoice is a preliminary invoice sent by a seller to a buyer before the actual goods are delivered. It outlines the description of the goods, their prices, and the terms of sale, including payment terms. In many cases, a proforma invoice includes a request for immediate payment, often in advance of the goods being shipped or delivered. It serves as a formal quotation and can be used for various purposes, including customs clearance and as a basis for arranging payment.</div>", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING"}, {"id": "objective>Commerce>1999>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following document permit an importer to inspect his goods before the arrival of the bill of lading?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Bill of sight</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Import invoice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Consular invoice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bill of exchange</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A Bill of Sight is a document that allows an importer to inspect his goods before the arrival of the bill of lading. It is a temporary document detailing the particulars of the goods that are yet to be inspected in detail. The other options do not serve this purpose. An import invoice is a document provided by the seller to the buyer, detailing the type and value of goods sold. A consular invoice is a document used in foreign trade transactions, certified by the consul of the importing country residing in the foreign country from where the goods are being shipped. A bill of exchange is a written order binding one party to pay a fixed sum of money to another party on demand or at a predetermined date.</div>", "topic": "TRADE ( 2) : DOCMENT USED IN INTERNATION TRADE"}, {"id": "objective>Commerce>1999>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The overriding advantage of home trade over foreign trade is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">accessibility of seller to buyer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">absence of many documents</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ease in language of transaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ease in form of payment</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In home trade, the buyer and seller are typically located within the same country or a relatively close geographical region. This physical proximity makes it easier for them to access each other, communicate, and conduct business transactions. In contrast, foreign trade involves dealing with parties in different countries, which can result in greater distances, time zone differences, and cultural and language barriers. These factors can make it more challenging to access and communicate with foreign buyers and sellers. Therefore, the accessibility of the seller to the buyer is a significant advantage of home trade.</div>", "topic": "TRADE ( 2) : FOREIGN TRADE"}, {"id": "objective>Commerce>1999>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A distinction between Comprehensive insurance and Third party Insurance is that the latter covers damages</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">caused by the insured vehicle</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> to the insured vehicle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cause by the other vehicle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">to the driver of insured vehicle</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The third party fire and theft covers damaged to the vehicle as a result of fire and theft and the policy holder will be compensated in the event of losses suffered from fire and theft of the vehicle. <br/>  <br/> Comprehensive insurance covers the driver, the insured, third parties and sometimes the contents of the insured vehicle.</div>", "topic": "AIDS TO TRADE: INSURANCE : TERMS"}, {"id": "objective>Commerce>1999>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The rate at which a central bank discount first class bills is called the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fixed rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bill rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bank rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">interest rate</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bank rate is the rate charged on loans offered by the central bank to the commercial banks without any collateral. It is also considered as the rate at which the central bank discounts the bills of the commercial banks.</div>", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLEGES"}, {"id": "objective>Commerce>1999>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The principle of subrogation states that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an insured person should be indemnify to the tune of the amount insured</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an insurance company can stand in place of the insured in dealing with third party </div>", "<div style=\"font-family:Cambria;font-size:17px;\">only a person who is likely to suffer loss should take take out an insurance cover</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there must be a close connection between the actual loss suffered and risk insured</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Under the principle of subrogation, once the insurer has given an indemnity for loss, he can take over the subject matter of the insurance and the rights relating to it. The principle implies that the insurance company can take over the rights of the insured once he has been compensated.</div>", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES"}, {"id": "objective>Commerce>1999>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Tolu purchase goods from Yemisi and is to pay custom duties before collection. The goods are likely to be collected from.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a manufacturer's warehouse</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a bonded warehouse</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an importer's warehouse </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a wholesaler's warehouse</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bonded warehouse is a place where goods whose custom duties have not been paid are stored until the duties are settled.</div>", "topic": "AIDS TO TRADE: WAREHOUSING: : TYPES & IMPORTANCE"}, {"id": "objective>Commerce>1999>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The three major function unit which the modern computer has are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the input the processor and the output units</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the black box, output and input units</div>", "<div style=\"font-family:Cambria;font-size:17px;\">BASIC, COBOL and output units</div>", "<div style=\"font-family:Cambria;font-size:17px;\">BASIC, the processor and PASCAL</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The three major functional units of a modern computer are the input unit, the processor (or central processing unit, CPU), and the output unit. The input unit is responsible for taking in data and instructions, the processor processes the data according to the instructions, and the output unit displays the results.</div>", "topic": "INFORMATIONAND COMMUNICATION TECHNOLOGY (ICT) : TYPES OF COMPUTER AND FUNCTIONS"}, {"id": "objective>Commerce>1999>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">i. Foreign investment  <br/> ii. Long term lending <br/> iii. Short-term borrowing.  <br/>  <br/> Which combination of the above include capital account in international trade?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">i, iii, and iv</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ii, iii and iv</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ii and iv</div>", "<div style=\"font-family:Cambria;font-size:17px;\">i and ii</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In international trade, the capital account includes foreign investment and long-term lending. Foreign investment refers to the investment by a company or individual of one country into another country. Long-term lending refers to loans that are due in more than one year. Therefore, the correct combination is i and ii.</div>", "topic": "TRADE ( 2) : FOREIGN TRADE"}, {"id": "objective>Commerce>1999>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The elimination of fault in a computer programme is called?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">console</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debug</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dump</div>", "<div style=\"font-family:Cambria;font-size:17px;\">loop</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The elimination of faults in a computer program is called debugging. Debugging is the process of finding and resolving defects or problems within a computer program that prevent correct operation of computer software or a system.</div>", "topic": "INFORMATIONAND COMMUNICATION TECHNOLOGY (ICT) : ACTIVITIES IN COMPUTER"}, {"id": "objective>Commerce>1999>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Aliyu bought 100 shares at the stock market through a stockbroker. He was told the price of each share was N3 cum. div. This means that Aliyu</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">is entitled always to a cumulative dividends accruing from the shares</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is entitled to the next dividends due to the shares</div>", "<div style=\"font-family:Cambria;font-size:17px;\">will not be entitled to the next dividends due to the shares</div>", "<div style=\"font-family:Cambria;font-size:17px;\">still owes N3 on the shares which will be subtracted from the dividends</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cum div denotes price at which the holder of such shares has the right to receive the next dividend payable.</div>", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS"}, {"id": "objective>Commerce>1999>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The forum for the selling and of buying of securities of small and medium companies is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Second Tier Foreign Exchange Market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Foreign Exchange Market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Securities and Exchange Commission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Second Tier Securities</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Second Tier Securities market is an alternative to the main market to meet the desire of the small and medium scale enterprises who want to raise money from the capital market.</div>", "topic": "STOCK EXCHANGE : SECOND- TIER SECURITIES MARKET"}, {"id": "objective>Commerce>1999>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A wholesale dealer in securities is known as a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">stockbroker</div>", "<div style=\"font-family:Cambria;font-size:17px;\">speculator</div>", "<div style=\"font-family:Cambria;font-size:17px;\">jobber</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stag</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A jobber is a dealer in the stock exchange market who transact with the speculators (bear, bull and stag). He receives commission known as jobber's turn.</div>", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS"}, {"id": "objective>Commerce>1999>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Modern business philosophy emphasizes</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">quality products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">customer satisfaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sales volume </div>", "<div style=\"font-family:Cambria;font-size:17px;\">public relations</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A business philosophy is a set of guiding principles that a business strives towards to reach its ultimate goal. At its very core are the customer and his or her satisfaction.</div>", "topic": "ELEMENT OF MARKETING : THE MARKETING CONCEPT"}, {"id": "objective>Commerce>1999>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main role of advertising is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">convince prospective buyers to buy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">show the actual shape, form and colour of the products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inform people where to obtain goods and services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">captured the attention of people</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When business firm offer similar products, the firm must not only inform the customers about the product's availability but also persuade them to buy it.</div>", "topic": "AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES"}, {"id": "objective>Commerce>1999>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The concept of limiting types, sizes and other characteristics of a product line without sacrificing utility or durability is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">simplification</div>", "<div style=\"font-family:Cambria;font-size:17px;\">standardization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">specialization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">satisfying</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The concept of limiting types, sizes and other characteristics of a product line without sacrificing utility or durability is called standardization.</div>", "topic": "ELEMENT OF MARKETING : MARKETING MIX"}, {"id": "objective>Commerce>1999>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The focal point of the marketing efforts is the`</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">seller</div>", "<div style=\"font-family:Cambria;font-size:17px;\">profit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">product</div>", "<div style=\"font-family:Cambria;font-size:17px;\">buyer</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The focal point of the marketing efforts is the buyer. Marketing is about understanding the customer's needs and creating, communicating and delivering value that meets those needs. Therefore, the buyer is the center of all marketing efforts.</div>", "topic": "ELEMENT OF MARKETING : THE MARKETING CONCEPT"}, {"id": "objective>Commerce>1999>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Adigun displays goods of different makes on shelves in his supermarket. This is an example of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">invitation to treat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">offer to sell</div>", "<div style=\"font-family:Cambria;font-size:17px;\">offer to purchase</div>", "<div style=\"font-family:Cambria;font-size:17px;\">invitation to sell</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This is an invitation to another person to make offer. It is not an offer, therefore it cannot be accepted.</div>", "topic": "TRADE (1) : HOME TRADE: RETAIL TRADE"}, {"id": "objective>Commerce>1999>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The process of bringing a company under exclusive state ownership and control is know as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nationalization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">commercialization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">indigenization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">privatization</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nationalisation is a deliberate policy by which government takes over the control and ownership of private enterprises due to economic, political, social or strategic reasons.</div>", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES"}, {"id": "objective>Commerce>1999>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Q,acting as the agent of P, lawfully and reasonably incurs the amount of N350 as expenses.If Q comes to P, for payment , this is an instance of P'S duty to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">remunerate Q</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reply Q</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> indemnify Q</div>", "<div style=\"font-family:Cambria;font-size:17px;\">settle Q</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In agency law, if an agent incurs expenses in the course of performing his duties, the principal has a duty to indemnify the agent. Indemnification means compensating someone for harm or loss. In this case, P (the principal) has a duty to indemnify Q (the agent) for the N350 expenses that Q incurred while acting as P's agent.</div>", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT"}, {"id": "objective>Commerce>1999>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a hire purchase agreement between Argungu Ltd and Maikudi, Argungu Ltd inserted provision that it can enter Maikudi's premises at any time and remove the hired vehicle for any breach. This provision is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lawful to both</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unlawful to both</div>", "<div style=\"font-family:Cambria;font-size:17px;\">beneficial to both</div>", "<div style=\"font-family:Cambria;font-size:17px;\">detrimental to both</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Since the contract is documented, then it is lawful to both parties. Any party who breached the contract will be sue for damages.</div>", "topic": "LEGAL ASPECT OF BUSINESS: HIRE PURCHASES : MEANING AND TYPES"}, {"id": "objective>Commerce>1999>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In every simple contract, the price which is paid to purchase a promise is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">offeree </div>", "<div style=\"font-family:Cambria;font-size:17px;\">acceptance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consideration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">representation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">All simple contract must be supported by valuable consideration, that is, some elements of exchange which is measurable in money or money's worth.</div>", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT"}, {"id": "objective>Commerce>1999>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One major disadvantage of a cartel is that it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">maximizes productive efficiency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">brings the merging firms under control</div>", "<div style=\"font-family:Cambria;font-size:17px;\">maximizes profit from operation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">eliminate competitions and waste</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">CARTEL is an association of independent producers, formed mainly for the main purpose of regulating prices by controlling output. CARTEL discourage new entrants into the market, acting as a barrier to entry and it reduce waste by eliminating competition.</div>", "topic": "BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER"}, {"id": "objective>Commerce>1999>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Staff position in an organization borders on</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">authority</div>", "<div style=\"font-family:Cambria;font-size:17px;\">advice </div>", "<div style=\"font-family:Cambria;font-size:17px;\">responsibility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">control</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Staff positions in an organization are advisory in nature. They provide support, advice, and services to the line managers who are directly involved in achieving the organization's main objectives. Therefore, the correct answer is 'advice'.</div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE"}, {"id": "objective>Commerce>1999>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The line function in a typical manufacturing enterprise is normally performed by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">public relations department</div>", "<div style=\"font-family:Cambria;font-size:17px;\">estate or properties department</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marketing department</div>", "<div style=\"font-family:Cambria;font-size:17px;\">legal department</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Line function of organisational structure refers to direct working relationship between the subordinates and the superiors in which the line authority and responsibilities flow from the top executives to the lowest subordinates. It allows authority to flow downwards and responsibility upward.</div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE"}, {"id": "objective>Commerce>1999>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">i. Money and machines  <br/> ii. Materials and Money  <br/> iii. Market and Man. <br/>  <br/> Which combination of the above are basic requirement as business resource?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">i and ii</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ii and iii</div>", "<div style=\"font-family:Cambria;font-size:17px;\">i and iv</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ii and iv</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The basic requirements as business resources are Materials and Money (ii), and Market and Man (iii). Materials and money are needed to produce goods or services, and market and man are needed to sell the goods or services and manage the business. Therefore, the correct answer is 'ii and iii'.</div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : BUSINESS RESOURCES"}, {"id": "objective>Commerce>1999>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Under what management function would the motivation employees fall?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">planning</div>", "<div style=\"font-family:Cambria;font-size:17px;\">controlling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">organizing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">directing</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Directing involves getting people to carry out the decisions quickly, efficiently and with minimum fuss. Directing entails using leadership, motivation and other skills to ensure that people in the organisation know what their work is and have it.</div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : PRINCIPLE"}, {"id": "objective>Commerce>1999>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main thrust of government policy of evolving good business environment in Nigeria is the need</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">to attract local and foreign investors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">for more export commodities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">for consumer oriented products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">to have viable local markets</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The main thrust of government policy of evolving good business environment in Nigeria is the need to attract local and foreign investors.</div>", "topic": "BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITY : FACTORS"}, {"id": "objective>Commerce>1999>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these sets of external environmental factors affects a business operation?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Competition, industry operation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Competition, labour and political</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Political, cultural and labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Economic, social and legal</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Economic, social and legal are external factors that affect the operation of a business. Others include, political, social, cultural etc.</div>", "topic": "BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITY : FACTORS"}, {"id": "objective>Commerce>1999>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The right of the public to protection against questionable products and marketing practices is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an economic aspect of the business</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> a social responsibility of business</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a legal aspect of the business</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a political aspect of the business</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The right of the public to protection against questionable products and marketing practices is a social responsibility of business. This is because businesses have an obligation to ensure that their products are safe for consumption and that their marketing practices are ethical and do not mislead or harm the public.</div>", "topic": "BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITY : MEANING AND TYPES"}, {"id": "objective>Commerce>1999>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following group of countries are members of the Niger Basin Commission?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The republic of Guinea, Burkina Faso and Nigeria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ghana, liberia, and the republic of Benin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mali, Liberia and Nigeria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ghana , Burkina Faso and Chad</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The countries in Niger Basin Commission are: The Republic of Benin, Chad, Cameroun, Guinea, Burkina Faso, Nigeria, Mali, Cote de Ivoire and Niger Republic.</div>", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC."}, {"id": "objective>Commerce>1999>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The proposed monetary integration within ECOWAS sub-region has the overriding benefit of a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">improved exchange</div>", "<div style=\"font-family:Cambria;font-size:17px;\">enhanced trade</div>", "<div style=\"font-family:Cambria;font-size:17px;\">enhanced development</div>", "<div style=\"font-family:Cambria;font-size:17px;\">improved relations</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To expand trade among countries by widening the markets in the region is one of the proposed monetary integration within ECOWAS sub-region.</div>", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC."}];
